import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../hooks/usecart';
import { ChevronLeft, MapPin, ShieldCheck, AlertCircle, Loader2 } from 'lucide-react';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items = [] } = useCart();

  // Clean cart items
  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  // Redirect to cart if empty
  useEffect(() => {
    if (validItems.length === 0) {
      navigate('/cart');
    }
  }, [validItems, navigate]);

  // Form State
  const [formData, setFormData] = useState({
    fullName: 'Anand',
    phone: '',
    address1: '',
    address2: '',
    city: '',
    state: '',
    pincode: ''
  });

  // Premium Validation & Fetching States
  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState({ show: false, message: '', type: 'error' });
  const [isFetchingPincode, setIsFetchingPincode] = useState(false);
  const toastTimer = useRef(null);

  const showToast = (message, type = 'error') => {
    if (toastTimer.current) clearTimeout(toastTimer.current);
    setToast({ show: true, message, type });
    toastTimer.current = setTimeout(() => {
      setToast({ show: false, message: '', type: 'error' });
    }, 4000);
  };

  // ========================================================
  // 🚀 PREMIUM FEATURE: Auto-Fetch City & State by Pincode
  // ========================================================
  useEffect(() => {
    const fetchLocation = async () => {
      const pin = formData.pincode.replace(/\D/g, '');

      if (pin.length === 6) {
        setIsFetchingPincode(true);
        try {
          const response = await fetch(`https://api.postalpincode.in/pincode/${pin}`);
          const data = await response.json();

          if (data && data[0] && data[0].Status === 'Success' && data[0].PostOffice && data[0].PostOffice.length > 0) {
            const po = data[0].PostOffice[0];
            // Get the most accurate city/district name
            const fetchedCity = po.District || po.Block || po.Region || '';
            const fetchedState = po.State || '';

            setFormData(prev => ({
              ...prev,
              city: fetchedCity,
              state: fetchedState
            }));

            // Clear any existing errors for these fields
            setErrors(prev => ({ ...prev, city: false, state: false, pincode: false }));
            showToast('Location auto-filled successfully!', 'success');
          } else {
            setErrors(prev => ({ ...prev, pincode: true }));
            showToast('Invalid Pincode. Please check again.', 'error');
          }
        } catch (error) {
          console.error("Error fetching pincode details:", error);
          // We fail silently so the user can just type it in manually if the API goes down
        } finally {
          setIsFetchingPincode(false);
        }
      }
    };

    // Slight delay (debounce) to ensure user finished typing
    const timeoutId = setTimeout(() => {
      fetchLocation();
    }, 400);

    return () => clearTimeout(timeoutId);
  }, [formData.pincode]);

  // Math Calculations (Subtotal + 18% GST)
  const subtotal = validItems.reduce((acc, item) => {
    const price = Number(item.price) || 0;
    const qty = Number(item.quantity) || 1;
    return acc + (price * qty);
  }, 0);

  const gst = Math.round(subtotal * 0.18);
  const total = subtotal + gst;

  const handleInputChange = (e) => {
    const { name, value } = e.target;

    // If they are typing in pincode, strictly allow only numbers
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;

    setFormData(prev => ({ ...prev, [name]: value }));

    // Smooth UX: Remove the red error border the moment the user starts typing
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: false }));
    }
  };

  const handleContinuePayment = () => {
    // 1. Identify missing required fields
    const requiredFields = ['fullName', 'phone', 'address1', 'city', 'state', 'pincode'];
    const newErrors = {};

    requiredFields.forEach(field => {
      if (!formData[field].trim()) {
        newErrors[field] = true;
      }
    });

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      showToast('Please fill in all required shipping details.', 'error');
      return;
    }

    // 2. Validate Phone Number (Basic 10 digit check)
    if (formData.phone.replace(/\D/g, '').length < 10) {
      setErrors({ phone: true });
      showToast('Please enter a valid 10-digit phone number.', 'error');
      return;
    }

    // 3. Validate City (Letters and spaces only)
    if (!/^[a-zA-Z\s]+$/.test(formData.city.trim())) {
      setErrors({ city: true });
      showToast('Please enter a valid City name (letters only).', 'error');
      return;
    }

    // 4. Validate State (Letters and spaces only)
    if (!/^[a-zA-Z\s]+$/.test(formData.state.trim())) {
      setErrors({ state: true });
      showToast('Please enter a valid State name (letters only).', 'error');
      return;
    }

    // 5. Validate Pincode (6 digits)
    if (formData.pincode.replace(/\D/g, '').length !== 6) {
      setErrors({ pincode: true });
      showToast('Please enter a valid 6-digit pincode.', 'error');
      return;
    }

    // If everything is perfect, proceed to payment!
    console.log("Proceeding to payment with:", formData);
    alert("Validation Passed! Ready to move to Payment Gateway.");
  };

  return (
    <div className="bg-[#f8f9fa] min-h-screen py-8 md:py-10 font-sans relative">

      {/* ========================================================
          🚀 PREMIUM TOAST NOTIFICATION 
          ======================================================== */}
      <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[200] transition-all duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] pointer-events-none flex justify-center ${toast.show ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 -translate-y-6 scale-95'}`}>
        <div className={`bg-white/95 backdrop-blur-xl border shadow-[0_10px_40px_-10px_rgba(0,0,0,0.15)] text-gray-800 px-5 py-3 rounded-full flex items-center gap-3 w-max max-w-[90vw] ${toast.type === 'success' ? 'border-green-100' : 'border-red-100'}`}>
          <div className={`${toast.type === 'success' ? 'bg-green-50' : 'bg-red-50'} p-1 rounded-full shrink-0`}>
            {toast.type === 'success' ? (
              <ShieldCheck size={16} className="text-green-500" strokeWidth={2.5} />
            ) : (
              <AlertCircle size={16} className="text-red-500" strokeWidth={2.5} />
            )}
          </div>
          <span className="text-[13px] font-semibold tracking-tight">{toast.message}</span>
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-6xl">

        <div className="mb-6">
          <button
            onClick={() => navigate('/cart')}
            className="inline-flex items-center text-sm font-bold text-orange-500 hover:text-orange-600 transition-colors group outline-none focus:outline-none focus:ring-0 focus-visible:outline-none border-none bg-transparent select-none"
            style={{ WebkitTapHighlightColor: 'transparent' }}
          >
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            Return to Cart
          </button>
        </div>

        <div className="flex items-center mb-6">
          <h1 className="text-[28px] font-black text-gray-900 tracking-tight">Checkout</h1>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* ========================================================
              LEFT COLUMN: PREMIUM SHIPPING FORM
              ======================================================== */}
          <div className="lg:col-span-7 flex flex-col gap-6">
            <div className="bg-white rounded-[20px] shadow-sm border border-gray-100 p-6 md:p-8">

              <div className="flex items-center gap-3 mb-8 border-b border-gray-50 pb-5">
                <div className="bg-[#5c4033] text-white p-2 rounded-full shadow-sm">
                  <MapPin size={20} strokeWidth={2} />
                </div>
                <h2 className="text-lg font-bold text-gray-900">Shipping Address</h2>
              </div>

              {/* FORM GRID WITH LABELS AND NO DOUBLE-OUTLINES */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-5 gap-y-6">

                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Full Name *</label>
                  <input
                    type="text" name="fullName" value={formData.fullName} onChange={handleInputChange}
                    className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border ${errors.fullName ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                    placeholder="e.g. John Doe"
                  />
                </div>

                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Phone Number *</label>
                  <input
                    type="tel" name="phone" value={formData.phone} onChange={handleInputChange} maxLength="10"
                    className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border ${errors.phone ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                    placeholder="e.g. 9876543210"
                  />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Address Line 1 *</label>
                  <input
                    type="text" name="address1" value={formData.address1} onChange={handleInputChange}
                    className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border ${errors.address1 ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                    placeholder="House No., Building Name, Street"
                  />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Address Line 2 (Optional)</label>
                  <input
                    type="text" name="address2" value={formData.address2} onChange={handleInputChange}
                    className="w-full bg-white border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:border-orange-500 focus:outline-none focus:ring-0 transition-all placeholder:text-gray-400"
                    placeholder="Locality, Area, Landmark"
                  />
                </div>

                <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-5">
                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">City *</label>
                    <input
                      type="text" name="city" value={formData.city} onChange={handleInputChange}
                      className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border ${errors.city ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                      placeholder="e.g. Hyderabad"
                    />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">State *</label>
                    <input
                      type="text" name="state" value={formData.state} onChange={handleInputChange}
                      className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border ${errors.state ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                      placeholder="e.g. Telangana"
                    />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Pincode *</label>
                    <div className="relative">
                      <input
                        type="text" name="pincode" value={formData.pincode} onChange={handleInputChange} maxLength="6"
                        className={`w-full text-sm rounded-xl px-4 py-3.5 transition-all outline-none focus:outline-none focus:ring-0 placeholder:text-gray-400 border pr-10 ${errors.pincode ? 'bg-red-50 border-red-300 focus:border-red-500' : 'bg-white border-gray-200 focus:border-orange-500'}`}
                        placeholder="e.g. 500001"
                      />
                      {/* Loading Spinner during API Fetch */}
                      {isFetchingPincode && (
                        <div className="absolute right-3 top-1/2 -translate-y-1/2">
                          <Loader2 size={18} className="text-orange-500 animate-spin" />
                        </div>
                      )}
                    </div>
                  </div>
                </div>

              </div>

              <div className="mt-8 pt-6 flex md:justify-start">
                <button
                  onClick={handleContinuePayment}
                  className="w-full md:w-auto bg-[#5c4033] text-white px-10 py-3.5 rounded-xl font-bold tracking-wide hover:bg-[#4a332a] hover:shadow-lg hover:shadow-[#5c4033]/20 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none focus:ring-0 select-none border-none"
                >
                  Continue to Payment
                </button>
              </div>

            </div>
          </div>

          {/* ========================================================
              RIGHT COLUMN: PREMIUM ORDER SUMMARY
              ======================================================== */}
          <div className="lg:col-span-5 flex flex-col gap-6 md:sticky md:top-28">
            <div className="bg-white rounded-[20px] shadow-sm border border-gray-100 p-6 md:p-8">

              <h3 className="text-[17px] font-bold text-gray-900 mb-6 tracking-tight border-b border-gray-50 pb-4">Order Summary</h3>

              {/* Items List */}
              <div className="flex flex-col gap-4 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar mb-6">
                {validItems.map((item, index) => {
                  const itemPrice = Number(item.price) || 0;
                  const itemQty = Number(item.quantity) || 1;

                  return (
                    <div key={index} className="flex items-center gap-4 group">
                      <div className="w-16 h-16 bg-gray-50 rounded-xl overflow-hidden border border-gray-100 shrink-0 relative">
                        <img
                          src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=200&q=80'}
                          alt={item.name}
                          className="w-full h-full object-cover"
                          onError={(e) => { e.target.onerror = null; e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=200&q=80'; }}
                        />
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="text-sm font-medium text-gray-900 truncate">{item.name || 'Premium Item'}</h4>
                        <p className="text-[11px] font-medium text-gray-500 mt-0.5">Qty: {itemQty}</p>
                      </div>
                      <div className="text-sm font-bold text-gray-900 shrink-0">
                        ₹{(itemPrice * itemQty).toLocaleString('en-IN')}
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Price Breakdown */}
              <div className="space-y-3 pt-5 border-t border-gray-50">
                <div className="flex justify-between items-center text-[13px]">
                  <span className="text-gray-500 font-medium">Subtotal</span>
                  <span className="text-gray-900 font-bold">₹{subtotal.toLocaleString('en-IN')}</span>
                </div>
                <div className="flex justify-between items-center text-[13px]">
                  <span className="text-gray-500 font-medium">Shipping</span>
                  <span className="text-[#16a34a] font-bold tracking-wide">Free</span>
                </div>
                <div className="flex justify-between items-center text-[13px]">
                  <span className="text-gray-500 font-medium">GST (18%)</span>
                  <span className="text-gray-900 font-bold">₹{gst.toLocaleString('en-IN')}</span>
                </div>
              </div>

              {/* Total */}
              <div className="mt-5 pt-5 border-t border-gray-100 border-dashed">
                <div className="flex justify-between items-center">
                  <span className="text-[17px] font-black text-gray-900 tracking-tight">Total</span>
                  <span className="text-xl font-black text-gray-900 tracking-tight">₹{total.toLocaleString('en-IN')}</span>
                </div>
              </div>

            </div>

            {/* Trust Badge */}
            <div className="flex items-center justify-center gap-2 text-xs text-gray-500 font-medium pb-4">
              <ShieldCheck size={16} className="text-green-600" />
              <span>100% Safe & Secure Checkout</span>
            </div>

          </div>

        </div>
      </div>

      <style jsx="true">{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent; 
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e5e7eb; 
          border-radius: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #d1d5db; 
        }
      `}</style>
    </div>
  );
};

export default CheckoutPage;
